  20→/** @file*/
  21→
  22→#include "internal_nn_math.h"
  23→#include "riscv_nn_support.h"
  24→
  25→//// Convolution Functions
  26→int32_t riscv_nn_conv_HWC_u8_u8_s8_sym_bias_fast_any(const u8_t * in_tensor,
  27→        const uint16_t in_tensor_dim_x,
  28→        const uint16_t in_tensor_dim_y,
  29→        const uint16_t in_tensor_ch,
  30→        const q7_t * ker_weight,
  31→        const uint16_t out_tensor_ch,
  32→        const uint16_t ker_dim_x,
  33→        const uint16_t ker_dim_y,
  34→        const uint16_t pad_x,
  35→        const uint16_t pad_y,
  36→        const uint16_t stride_x,
  37→        const uint16_t stride_y,
  38→        const q31_t * bias,
  39→        const uint16_t pre_rshift,
  40→        const uint16_t out_scale,
  41→        const uint16_t post_rshift,
  42→        u8_t * out_tensor,
  43→        const uint16_t out_tensor_dim_x,
  44→        const uint16_t out_tensor_dim_y,
  45→        q15_t * in_tmp_buf)
  46→{
  47→#ifdef ENA_EMPTY_FUN
  48→    //empty body
  49→#else
  50→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
  51→    {
  52→        /* check if the input dimension meets the constraints */
  53→        return -1;
  54→    }
  55→
  56→#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
  57→    /* cache is 512KB, type is q7 */
  58→    uint32_t tiling_size = 256;
  59→    /* num of columnar */
  60→    int col_counter = 0;
  61→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
  62→    unsigned long addr_in_tmp_buf;
  63→
  64→    /*
  65→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
  66→     *  im2col are done to output in q15_t format from u8_t input
  67→     */
  68→    const long align_byte = 64;
  69→    u8_t *pBuffer = (u8_t*)in_tmp_buf;
  70→    u8_t *pOut = out_tensor;
  71→    q31_t *dst_q31;
  72→
  73→    q7_t *src2 = (q7_t *)in_tmp_buf
  74→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y; //matrix_A's memory space
  75→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
  76→    addr_in_tmp_buf = (unsigned long)src2;
  77→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
  78→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
  79→    dst_q31 = (q31_t *)addr_in_tmp_buf;
  80→
  81→    /* transpose the kernel_weight for matrix multiplication */
  82→    const long row = out_tensor_ch;
  83→    const long col = ker_dim_x * ker_dim_y * in_tensor_ch;
  84→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
  85→
  86→    /* This part implements the im256col function */
  87→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
  88→    {
  89→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
  90→        {
  91→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
  92→            {
  93→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
  94→                {
  95→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
  96→                    {
  97→                        /* Filling 0 for out-of-bound paddings */
  98→                        nn_set_zero_u8(pBuffer, sizeof(u8_t) * in_tensor_ch);
  99→                    }
 100→                    else
 101→                    {
 102→                        /* Copying the pixel data to column */
 103→                        nn_dup_u8(in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
 104→                    }
 105→                    pBuffer += in_tensor_ch;
 106→                }
 107→            }
 108→            col_counter++;
 109→
 110→            /* Computation is filed for [tiling_size] columns */
 111→            if (col_counter == tiling_size)
 112→            {
 113→                pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
 114→                                                              src2,
 115→                                                              dst_q31,
 116→                                                              pOut,
 117→                                                              col_counter,
 118→                                                              in_tensor_ch * ker_dim_x * ker_dim_y,
 119→                                                              out_tensor_ch,
 120→                                                              pre_rshift,
 121→                                                              out_scale,
 122→                                                              post_rshift,
 123→                                                              bias,
 124→                                                              tiling_size);
 125→                /* reset */
 126→                col_counter = 0;
 127→                pBuffer = (u8_t *)in_tmp_buf;
 128→            }
 129→        }
 130→    }
 131→
 132→    /* check if there is left-over for compute */
 133→    pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8((u8_t *)in_tmp_buf,
 134→                                                  src2,
 135→                                                  dst_q31,
 136→                                                  pOut,
 137→                                                  col_counter,
 138→                                                  in_tensor_ch * ker_dim_x * ker_dim_y,
 139→                                                  out_tensor_ch,
 140→                                                  pre_rshift,
 141→                                                  out_scale,
 142→                                                  post_rshift,
 143→                                                  bias,
 144→                                                  tiling_size);
 145→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
 146→    int i_out_y, i_out_x, i_ker_y, i_ker_x;
 147→
 148→    /* -----------------------
 149→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 150→     *  im2col are done to output in q15_t format from q7_t input
 151→     */
 152→
 153→    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
 154→    u8_t     *pOut = out_tensor;
 155→    int bound_x_begin = (pad_x + stride_x - 1) / stride_x;
 156→    int bound_x_end   = (in_tensor_dim_x + pad_x - ker_dim_x + stride_x) / stride_x;
 157→    int bound_y_begin = (pad_y + stride_y - 1) / stride_y;
 158→    int bound_y_end   = (in_tensor_dim_y + pad_y - ker_dim_y + stride_y) / stride_y;
 159→
 160→    /*
 161→     *  Here we split the entire matrix into three regions depending on the padding situation
 162→     *    Top: i_out_y from 0 to padding - 1
 163→     * Middle: i_out_y from padding to dim_im_out-padding-1
 164→     * Bottom: i_out_y from dim_im_out-padding to dim_im_out-1
 165→     */
 166→
 167→    /* top part */
 168→    for (i_out_y = 0; i_out_y < bound_y_begin; i_out_y++)
 169→    {
 170→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
 171→        {
 172→            /* This part implements the im2col function */
 173→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
 174→            {
 175→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
 176→                {
 177→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 178→                    {
 179→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
 180→                    }
 181→                    else
 182→                    {
 183→                        nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
 184→                                      pBuffer, in_tensor_ch);
 185→                    }
 186→                    pBuffer += in_tensor_ch;
 187→                }
 188→            }
 189→
 190→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 191→            {
 192→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
 193→                        (u8_t*)in_tmp_buf,
 194→                        out_tensor_ch,
 195→                        in_tensor_ch * ker_dim_x * ker_dim_y,
 196→                        pre_rshift,
 197→                        out_scale,
 198→                        post_rshift,
 199→                        bias,
 200→                        pOut);
 201→                /* counter reset */
 202→                pBuffer = (u8_t *)in_tmp_buf;
 203→            }
 204→        }
 205→    }
 206→
 207→    /* middle part, here we also divide the x into left, mid and right */
 208→    for (; i_out_y < bound_y_end; i_out_y++)
 209→    {
 210→        /* left part */
 211→        for (i_out_x = 0; i_out_x < bound_x_begin; i_out_x++)
 212→        {
 213→            /* This part implements the im2col function */
 214→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
 215→                    i_ker_y++)
 216→            {
 217→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
 218→                        i_ker_x++)
 219→                {
 220→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 221→                    {
 222→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
 223→                    }
 224→                    else
 225→                    {
 226→                        nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
 227→                                      pBuffer, in_tensor_ch);
 228→                    }
 229→                    pBuffer += in_tensor_ch;
 230→                }
 231→            }
 232→
 233→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 234→            {
 235→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
 236→                        (u8_t *)in_tmp_buf,
 237→                        out_tensor_ch,
 238→                        in_tensor_ch * ker_dim_x * ker_dim_y,
 239→                        pre_rshift,
 240→                        out_scale,
 241→                        post_rshift,
 242→                        bias,
 243→                        pOut);
 244→                /* counter reset */
 245→                pBuffer = (u8_t*)in_tmp_buf;
 246→            }
 247→        }
 248→
 249→        /* mid part */
 250→        for (; i_out_x < bound_x_end; i_out_x++)
 251→        {
 252→            /* This part implements the im2col function */
 253→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
 254→                    i_ker_y++)
 255→            {
 256→                nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch,
 257→                              pBuffer, in_tensor_ch * ker_dim_x);
 258→                pBuffer += in_tensor_ch * ker_dim_x;
 259→            }
 260→
 261→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 262→            {
 263→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
 264→                        (u8_t*)in_tmp_buf,
 265→                        out_tensor_ch,
 266→                        in_tensor_ch * ker_dim_x * ker_dim_y,
 267→                        pre_rshift,
 268→                        out_scale,
 269→                        post_rshift,
 270→                        bias,
 271→                        pOut);
 272→                /* counter reset */
 273→                pBuffer = (u8_t*)in_tmp_buf;
 274→            }
 275→        }
 276→
 277→        /* right part */
 278→        for (; i_out_x < out_tensor_dim_x; i_out_x++)
 279→        {
 280→            /* This part implements the im2col function */
 281→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
 282→                    i_ker_y++)
 283→            {
 284→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
 285→                        i_ker_x++)
 286→                {
 287→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 288→                    {
 289→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
 290→                    }
 291→                    else
 292→                    {
 293→                        nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
 294→                                      pBuffer, in_tensor_ch);
 295→                    }
 296→                    pBuffer += in_tensor_ch;
 297→                }
 298→            }
 299→
 300→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 301→            {
 302→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
 303→                        (u8_t*)in_tmp_buf,
 304→                        out_tensor_ch,
 305→                        in_tensor_ch * ker_dim_x * ker_dim_y,
 306→                        pre_rshift,
 307→                        out_scale,
 308→                        post_rshift,
 309→                        bias,
 310→                        pOut);
 311→                /* counter reset */
 312→                pBuffer = (u8_t*)in_tmp_buf;
 313→            }
 314→        }
 315→    }
 316→
 317→    for (; i_out_y < out_tensor_dim_y; i_out_y++)
 318→    {
 319→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
 320→        {
 321→            /* This part implements the im2col function */
 322→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
 323→                    i_ker_y++)
 324→            {
 325→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
 326→                        i_ker_x++)
 327→                {
 328→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 329→                    {
 330→                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
 331→                    }
 332→                    else
 333→                    {
 334→                        nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
 335→                                      pBuffer, in_tensor_ch);
 336→                    }
 337→                    pBuffer += in_tensor_ch;
 338→                }
 339→            }
 340→
 341→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 342→            {
 343→                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
 344→                        (u8_t*)in_tmp_buf,
 345→                        out_tensor_ch,
 346→                        in_tensor_ch * ker_dim_x * ker_dim_y,
 347→                        pre_rshift,
 348→                        out_scale,
 349→                        post_rshift,
 350→                        bias,
 351→                        pOut);
 352→                /* counter reset */
 353→                pBuffer = (u8_t*)in_tmp_buf;
 354→            }
 355→        }
 356→    }
 357→
 358→    /* check if there is left-over for compute */
 359→#ifdef ENA_VEC_ISA
 360→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
 361→    if (pBuffer != (u8_t *)in_tmp_buf)
 362→    {
 363→        unsigned vl;
 364→        const q7_t *p_wt = ker_weight;
 365→        int       i;
 366→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
 367→
 368→        vl = __riscv_vsetvl_e32m1(1);
 369→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
 370→
 371→        for (i = 0; i < out_tensor_ch; i++)
 372→        {
 373→            u8_t      *p_in = (u8_t*)in_tmp_buf;
 374→            uint16_t colCnt2 = colCnt;
 375→
 376→            //clear v0~v7
 377→            vl = __riscv_vsetvl_e32m8(colCnt);
 378→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
 379→
 380→            while (colCnt2 > 0)
 381→            {
 382→                vl = __riscv_vsetvl_e8m8(colCnt2);
 383→                //load src1
 384→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
 385→                //load src2
 386→                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
 387→                //bump pointers and update loop counter
 388→                colCnt2 -= vl;
 389→                p_wt += vl;
 390→                p_in += vl;
 391→                //set the proper avl/SEW/LMUL values for vd4dot
 392→                vl >>= 2;
 393→                vl = __riscv_vsetvl_e32m8(vl);
 394→                //acc += src1 * src2
 395→                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
 396→            }
 397→
 398→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
 399→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
 400→
 401→            //add bias back
 402→            vl = __riscv_vsetvl_e32m1(1);
 403→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
 404→            vSum = __riscv_vadd(vSum, vBias, vl);
 405→
 406→            //2-stage shift
 407→            vSum = __riscv_vsra(vSum, pre_rshift, vl);
 408→            vSum = __riscv_vmul(vSum, out_scale, vl);
 409→            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
 410→
 411→            //scale down, clip and store the results
 412→            vSum = __riscv_vmax(vSum, 0, vl);
 413→            vl = __riscv_vsetvl_e16mf2(1);
 414→            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
 415→            vl = __riscv_vsetvl_e8mf4(1);
 416→            vuint16mf2_t vSum_u16mf2 = __riscv_vreinterpret_u16mf2(vSum_i16mf2);
 417→            vuint8mf4_t vpOut = __riscv_vnclipu(vSum_u16mf2, 0, __RISCV_VXRM_RNU, vl);
 418→            __riscv_vse8(pOut, vpOut, vl);
 419→            bias += vl;
 420→            pOut += vl;
 421→        }
 422→    }
 423→#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
 424→    if (pBuffer != (u8_t *)in_tmp_buf)
 425→    {
 426→        unsigned vl;
 427→        const q7_t *p_wt = ker_weight;
 428→        int       i;
 429→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
 430→
 431→        NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 432→        NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0x0);     //const zero for redsum
 433→
 434→        for (i = 0; i < out_tensor_ch; i++)
 435→        {
 436→            u8_t      *p_in = (u8_t*)in_tmp_buf;
 437→            uint16_t colCnt2 = colCnt;
 438→
 439→            //clear v0~v7
 440→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 441→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
 442→
 443→            while (colCnt2 > 0)
 444→            {
 445→                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
 446→                //load src1
 447→                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
 448→                //load src2
 449→                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
 450→                //bump pointers and update loop counter
 451→                colCnt2 -= vl;
 452→                p_wt += vl;
 453→                p_in += vl;
 454→                //set the proper avl/SEW/LMUL values for vd4dot
 455→                vl >>= 2;
 456→                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 457→                //acc += src1 * src2
 458→                NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
 459→            }
 460→
 461→            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);  //note the avl here
 462→            NDS_VEC_VREDSUM_VS(NDS_VEC_V8, NDS_VEC_V0, NDS_VEC_V31);
 463→
 464→            //add bias back
 465→            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 466→            NDS_VEC_VLW_V(NDS_VEC_V9, bias);
