 927→            /* basically each time it process 4 entries */
 928→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
 929→            while (colCnt)
 930→            {
 931→                q31_t     inA1, inA2;
 932→                q31_t     inB1, inB2;
 933→
 934→                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
 935→                inB1 = *__SIMD32(pB)++;
 936→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
 937→                inB2 = *__SIMD32(pB)++;
 938→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
 939→                colCnt--;
 940→            }
 941→
 942→            //since in_tensor_ch is multiple of 4 (input constraints), the
 943→            //following codes will not be reached
 944→            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
 945→            // while (colCnt)
 946→            // {
 947→            //     q7_t      inA1 = *pA++;
 948→            //     u16_t     inB1 = *pB++;
 949→            //     sum += inA1 * inB1;
 950→            //     colCnt--;
 951→            // }
 952→
 953→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 954→            *pOut++ = NDS_DSP_SAT((sum >> post_rshift), 8);
 955→        }
 956→    }
 957→#else
 958→    int       i, j, k, l, m, n;
 959→    int       conv_out;
 960→    int       in_row, in_col;
 961→
 962→    for (i = 0; i < out_tensor_ch; i++)
 963→    {
 964→        for (j = 0; j < out_tensor_dim_y; j++)
 965→        {
 966→            for (k = 0; k < out_tensor_dim_x; k++)
 967→            {
 968→                conv_out = bias[i];
 969→                for (m = 0; m < ker_dim_y; m++)
 970→                {
 971→                    for (n = 0; n < ker_dim_x; n++)
 972→                    {
 973→                        /* if-for implementation */
 974→                        in_row = stride_y * j + m - pad_y;
 975→                        in_col = stride_x * k + n - pad_x;
 976→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
 977→                        {
 978→                            for (l = 0; l < in_tensor_ch; l++)
 979→                            {
 980→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
 981→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
 982→                            }
 983→                        }
 984→                    }
 985→
 986→                }
 987→                if (conv_out < 0)
 988→                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = 0;
 989→                else
 990→                {
 991→                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 992→                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SAT((conv_out >> post_rshift), 8);
 993→                }
 994→            }
 995→        }
 996→    }
 997→#endif  //ENA_DSP_ISA
 998→#endif  //ENA_EMPTY_FUN
 999→
1000→    /* Return to application */
1001→    return 0;
1002→}
