 26→
 27→int32_t riscv_nn_conv_HWC_s8_s8_s8_sym_bias_fast_any(const q7_t * in_tensor,
 28→                                            const uint16_t in_tensor_dim_x,
 29→                                            const uint16_t in_tensor_dim_y,
 30→                                            const uint16_t in_tensor_ch,
 31→                                            const q7_t * ker_weight,
 32→                                            const uint16_t out_tensor_ch,
 33→                                            const uint16_t ker_dim_x,
 34→                                            const uint16_t ker_dim_y,
 35→                                            const uint16_t pad_x,
 36→                                            const uint16_t pad_y,
 37→                                            const uint16_t stride_x,
 38→                                            const uint16_t stride_y,
 39→                                            const q31_t * bias,
 40→                                            const uint16_t pre_rshift,
 41→                                            const uint16_t out_scale,
 42→                                            const uint16_t post_rshift,
 43→                                            q7_t * out_tensor,
 44→                                            const uint16_t out_tensor_dim_x,
 45→                                            const uint16_t out_tensor_dim_y,
 46→                                            q15_t * in_tmp_buf)
 47→{
 48→#ifdef ENA_EMPTY_FUN
 49→    //empty body
 50→#else
 51→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
 52→    {
 53→        /* check if the input dimension meets the constraints */
 54→        return -1;
 55→    }
 56→
 57→#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
 58→    /* cache is 512KB, type is q7 */
 59→    uint32_t tiling_size = 256;
 60→    /* num of columnar */
 61→    int col_counter = 0;
 62→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
 63→    unsigned long addr_in_tmp_buf;
 64→
 65→    /*
 66→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 67→     *  im2col are done to output in q15_t format from q7_t input
 68→     */
 69→    const long align_byte = 64;
 70→    q7_t *pBuffer = (q7_t*)in_tmp_buf;
 71→    q7_t *pOut = out_tensor;
 72→    q31_t *dst_q31;
 73→
 74→    q7_t *src2 = (q7_t *)in_tmp_buf
 75→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y; //matrix_A's memory space
 76→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
 77→    addr_in_tmp_buf = (unsigned long)src2;
 78→    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
 79→    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
 80→    dst_q31 = (q31_t *)addr_in_tmp_buf;
 81→
 82→    /* transpose the kernel_weight for matrix multiplication */
 83→    const long row = out_tensor_ch;
 84→    const long col = ker_dim_x * ker_dim_y * in_tensor_ch;
 85→    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
 86→
 87→    /* This part implements the im256col function */
 88→    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
 89→    {
 90→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
 91→        {
 92→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
 93→            {
 94→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
 95→                {
 96→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 97→                    {
 98→                        /* Filling 0 for out-of-bound paddings */
 99→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
100→                    }
101→                    else
102→                    {
103→                        /* Copying the pixel data to column */
104→                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
105→                    }
106→                    pBuffer += in_tensor_ch;
107→                }
108→            }
109→            col_counter++;
110→
111→            /* Computation is filed for [tiling_size] columns */
112→            if (col_counter == tiling_size)
113→            {
114→                pOut = nn_mat_mul_kernel_tiling_q7((q7_t *)in_tmp_buf,
115→                                                   src2,
116→                                                   dst_q31,
117→                                                   pOut,
118→                                                   col_counter,
119→                                                   in_tensor_ch * ker_dim_x * ker_dim_y,
120→                                                   out_tensor_ch,
121→                                                   pre_rshift,
122→                                                   out_scale,
123→                                                   post_rshift,
124→                                                   bias,
125→                                                   tiling_size);
126→                /* reset */
127→                col_counter = 0;
128→                pBuffer = (q7_t *)in_tmp_buf;
129→            }
130→        }
131→    }
132→
133→    /* check if there is left-over for compute */
134→    pOut = nn_mat_mul_kernel_tiling_q7((q7_t*)in_tmp_buf,
135→                                       src2,
136→                                       dst_q31,
137→                                       pOut,
138→                                       col_counter,
139→                                       in_tensor_ch * ker_dim_x * ker_dim_y,
140→                                       out_tensor_ch,
141→                                       pre_rshift,
142→                                       out_scale,
143→                                       post_rshift,
144→                                       bias,
145→                                       tiling_size);
146→#elif defined(ENA_VEC_ISA) || defined(ENA_DSP_ISA_V5)
147→    int i_out_y, i_out_x, i_ker_y, i_ker_x;
148→
149→    /* -----------------------
150→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
151→     *  im2col are done to output in q15_t format from q7_t input
152→     */
153→
154→    q7_t     *pBuffer = (q7_t*)in_tmp_buf;
155→    q7_t     *pOut = out_tensor;
156→    int bound_x_begin = (pad_x + stride_x - 1) / stride_x;
157→    int bound_x_end   = (in_tensor_dim_x + pad_x - ker_dim_x + stride_x) / stride_x;
158→    int bound_y_begin = (pad_y + stride_y - 1) / stride_y;
159→    int bound_y_end   = (in_tensor_dim_y + pad_y - ker_dim_y + stride_y) / stride_y;
160→
161→    /*
162→     *  Here we split the entire matrix into three regions depending on the padding situation
163→     *    Top: i_out_y from 0 to padding - 1
164→     * Middle: i_out_y from padding to dim_im_out-padding-1
165→     * Bottom: i_out_y from dim_im_out-padding to dim_im_out-1
166→     */
167→
168→    /* top part */
169→    for (i_out_y = 0; i_out_y < bound_y_begin; i_out_y++)
170→    {
171→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
172→        {
173→            /* This part implements the im2col function */
174→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
175→            {
176→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
177→                {
178→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
179→                    {
180→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
181→                    }
182→                    else
183→                    {
184→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
185→                                    pBuffer, in_tensor_ch);
186→                    }
187→                    pBuffer += in_tensor_ch;
188→                }
189→            }
190→
191→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
192→            {
193→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
194→                                                      (q7_t*)in_tmp_buf,
195→                                                      out_tensor_ch,
196→                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
197→                                                      pre_rshift,
198→                                                      out_scale,
199→                                                      post_rshift,
200→                                                      bias,
201→                                                      pOut);
202→                /* counter reset */
203→                pBuffer = (q7_t *)in_tmp_buf;
204→            }
205→        }
206→    }
207→
208→    /* middle part, here we also divide the x into left, mid and right */
209→    for (; i_out_y < bound_y_end; i_out_y++)
210→    {
211→        /* left part */
212→        for (i_out_x = 0; i_out_x < bound_x_begin; i_out_x++)
213→        {
214→            /* This part implements the im2col function */
215→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
216→                    i_ker_y++)
217→            {
218→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
219→                        i_ker_x++)
220→                {
221→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
222→                    {
223→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
224→                    }
225→                    else
226→                    {
227→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
228→                                    pBuffer, in_tensor_ch);
229→                    }
230→                    pBuffer += in_tensor_ch;
231→                }
232→            }
233→
234→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
235→            {
236→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
237→                                                      (q7_t *)in_tmp_buf,
238→                                                      out_tensor_ch,
239→                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
240→                                                      pre_rshift,
241→                                                      out_scale,
242→                                                      post_rshift,
243→                                                      bias,
244→                                                      pOut);
245→                /* counter reset */
246→                pBuffer = (q7_t*)in_tmp_buf;
247→            }
248→        }
249→
250→        /* mid part */
251→        for (; i_out_x < bound_x_end; i_out_x++)
252→        {
253→            /* This part implements the im2col function */
254→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
255→                    i_ker_y++)
256→            {
257→                nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch,
258→                            pBuffer, in_tensor_ch * ker_dim_x);
259→                pBuffer += in_tensor_ch * ker_dim_x;
260→            }
261→
262→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
263→            {
264→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
265→                                                      (q7_t*)in_tmp_buf,
266→                                                      out_tensor_ch,
267→                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
268→                                                      pre_rshift,
269→                                                      out_scale,
270→                                                      post_rshift,
271→                                                      bias,
272→                                                      pOut);
273→                /* counter reset */
274→                pBuffer = (q7_t*)in_tmp_buf;
275→            }
276→        }
277→
278→        /* right part */
279→        for (; i_out_x < out_tensor_dim_x; i_out_x++)
280→        {
281→            /* This part implements the im2col function */
282→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
283→                    i_ker_y++)
284→            {
285→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
286→                        i_ker_x++)
287→                {
288→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
289→                    {
290→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
291→                    }
292→                    else
293→                    {
294→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
295→                                    pBuffer, in_tensor_ch);
296→                    }
297→                    pBuffer += in_tensor_ch;
298→                }
299→            }
300→
301→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
302→            {
303→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
304→                                                      (q7_t*)in_tmp_buf,
305→                                                      out_tensor_ch,
306→                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
307→                                                      pre_rshift,
308→                                                      out_scale,
309→                                                      post_rshift,
310→                                                      bias,
311→                                                      pOut);
312→                /* counter reset */
313→                pBuffer = (q7_t*)in_tmp_buf;
314→            }
315→        }
316→    }
317→
318→    for (; i_out_y < out_tensor_dim_y; i_out_y++)
319→    {
320→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
321→        {
322→            /* This part implements the im2col function */
323→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
324→                    i_ker_y++)
325→            {
326→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
327→                        i_ker_x++)
328→                {
329→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
330→                    {
331→                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
332→                    }
333→                    else
334→                    {
335→                        nn_dup_s8((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
336→                                    pBuffer, in_tensor_ch);
337→                    }
338→                    pBuffer += in_tensor_ch;
339→                }
340→            }
341→
342→            if (pBuffer == (q7_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
343→            {
344→                pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
345→                                                      (q7_t*)in_tmp_buf,
346→                                                      out_tensor_ch,
347→                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
348→                                                      pre_rshift,
349→                                                      out_scale,
350→                                                      post_rshift,
351→                                                      bias,
352→                                                      pOut);
353→                /* counter reset */
354→                pBuffer = (q7_t*)in_tmp_buf;
355→            }
356→        }
357→    }
358→
359→    /* check if there is left-over for compute */
360→#ifdef ENA_VEC_ISA
361→#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD) && defined(ENA_VEC_INTRINSIC)
362→    if (pBuffer != (q7_t *)in_tmp_buf)
363→    {
364→        unsigned vl;
365→        const q7_t *p_wt = ker_weight;
366→        int       i;
367→        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
368→
369→        vl = __riscv_vsetvl_e32m1(1);
370→        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
371→
372→        for (i = 0; i < out_tensor_ch; i++)
373→        {
374→            q7_t      *p_in = (q7_t*)in_tmp_buf;
375→            uint16_t colCnt2 = colCnt;
376→
377→            //clear v0~v7
378→            vl = __riscv_vsetvl_e32m8(colCnt);
379→            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
380→
381→            while (colCnt2 > 0)
382→            {
383→                vl = __riscv_vsetvl_e8m8(colCnt2);
384→                //load src1
385→                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
386→                //load src2
387→                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
388→                //bump pointers and update loop counter
389→                colCnt2 -= vl;
390→                p_wt += vl;
391→                p_in += vl;
392→                //set the proper avl/SEW/LMUL values for vd4dot
393→                vl >>= 2;
394→                vl = __riscv_vsetvl_e32m8(vl);
395→                //acc += src1 * src2
396→                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
397→            }
398→
399→            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
400→            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
401→
402→            //add bias back
403→            vl = __riscv_vsetvl_e32m1(1);
404→            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
405→            vSum = __riscv_vadd(vSum, vBias, vl);
406→
407→            //2-stage shift
408→            vSum = __riscv_vsra(vSum, pre_rshift, vl);
409→            vSum = __riscv_vmul(vSum, out_scale, vl);
410→            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
411→
412→            //scale down, clip and store the results
413→            vl = __riscv_vsetvl_e16mf2(1);
