880→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
881→            {
882→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
883→                {
884→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
885→                    {
886→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
887→                    }
888→                    else
889→                    {
890→                        nn_dup_s8_s16_reordered((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
891→                                                    pBuffer, in_tensor_ch);
892→                    }
893→                    pBuffer += in_tensor_ch;
894→                }
895→            }
896→
897→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
898→            {
899→                pOut =
900→                    nn_mat_mul_kernel_q7_q15_q7_reordered_bias_2sft(ker_weight,
901→                                                                    in_tmp_buf,
902→                                                                    out_tensor_ch,
903→                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
904→                                                                    pre_rshift,
905→                                                                    out_scale,
906→                                                                    post_rshift,
907→                                                                    bias,
908→                                                                    pOut);
909→                /* counter reset */
910→                pBuffer = in_tmp_buf;
911→            }
912→        }
913→    }
914→
915→    /* check if there is left-over for compute */
916→    if (pBuffer != in_tmp_buf)
917→    {
918→        const q7_t *pA = ker_weight;
919→        int       i;
920→        for (i = 0; i < out_tensor_ch; i++)
921→        {
922→            q31_t     sum = bias[i];
923→            q15_t    *pB = in_tmp_buf;
924→
925→            /* basically each time it process 4 entries */
926→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
927→            while (colCnt)
928→            {
929→                q31_t     inA1, inA2;
930→                q31_t     inB1, inB2;
931→
932→                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
933→                inB1 = *__SIMD32(pB)++;
934→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
935→                inB2 = *__SIMD32(pB)++;
936→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
937→                colCnt--;
938→            }
939→
940→            //since in_tensor_ch is multiple of 4 (input constraints), the
941→            //following codes will not be reached
942→            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
943→            // while (colCnt)
944→            // {
945→            //     q7_t      inA1 = *pA++;
946→            //     q15_t     inB1 = *pB++;
947→            //     sum += inA1 * inB1;
948→            //     colCnt--;
949→            // }
950→
951→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
952→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
953→        }
954→    }
955→#else
956→    int       i, j, k, l, m, n;
957→    int       conv_out;
958→    int       in_row, in_col;
959→
960→    for (i = 0; i < out_tensor_ch; i++)
961→    {
962→        for (j = 0; j < out_tensor_dim_y; j++)
963→        {
964→            for (k = 0; k < out_tensor_dim_x; k++)
965→            {
966→                conv_out = bias[i];
967→                for (m = 0; m < ker_dim_y; m++)
968→                {
969→                    for (n = 0; n < ker_dim_x; n++)
970→                    {
971→                        /* if-for implementation */
972→                        in_row = stride_y * j + m - pad_y;
973→                        in_col = stride_x * k + n - pad_x;
974→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
975→                        {
976→                            for (l = 0; l < in_tensor_ch; l++)
977→                            {
978→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
979→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
980→                            }
981→                        }
982→                    }
983→                }
984→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
985→                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
986→            }
987→        }
988→    }
989→#endif  //ENA_DSP_ISA
990→#endif  //ENA_EMPTY_FUN
991→
992→    /* Return to application */
993→    return 0;
994→}
