 41→        const uint16_t post_rshift,
 42→        q7_t * out_tensor,
 43→        const uint16_t out_tensor_dim_x,
 44→        const uint16_t out_tensor_dim_y,
 45→        q15_t * in_tmp_buf)
 46→{
 47→#ifdef ENA_EMPTY_FUN
 48→    //empty body
 49→#else
 50→    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0)
 51→    {
 52→        /* check if the input dimension meets the constraints */
 53→        return -1;
 54→    }
 55→
 56→#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
 57→    /* cache is 512KB, type is q7 */
 58→    uint32_t tiling_size = 256;
 59→    /* num of columnar */
 60→    int col_counter = 0;
 61→    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
 62→    unsigned long addr_in_tmp_buf;
 63→
 64→    /*
 65→     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
 66→     *  im2col are done to output in q15_t format from u8_t input
 67→     */
 68→    const long align_byte = 64;
 69→    u8_t *pBuffer = (u8_t*)in_tmp_buf;
 70→    q7_t *pOut = out_tensor;
 71→    q31_t *dst_q31;
 72→
 73→    q7_t *src2 = (q7_t *)in_tmp_buf
 74→                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y; //matrix_A's memory space
 75→    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
