837→        {
838→            /* This part implements the im2col function */
839→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
840→            {
841→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
842→                {
843→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
844→                    {
845→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
846→                    }
847→                    else
848→                    {
849→                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
850→                                                    pBuffer, in_tensor_ch);
851→                    }
852→                    pBuffer += in_tensor_ch;
853→                }
854→            }
855→
856→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
857→            {
858→                pOut =
859→                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
860→                                                                    (u16_t*)in_tmp_buf,
861→                                                                    out_tensor_ch,
862→                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
863→                                                                    pre_rshift,
864→                                                                    out_scale,
865→                                                                    post_rshift,
866→                                                                    bias,
867→                                                                    pOut);
868→                /* counter reset */
869→                pBuffer = (u16_t*)in_tmp_buf;
870→            }
871→        }
872→    }
873→
874→    for (; i_out_y < out_tensor_dim_y; i_out_y++)
875→    {
876→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
877→        {
878→            /* This part implements the im2col function */
879→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
880→            {
881→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
882→                {
883→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
884→                    {
885→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
886→                    }
887→                    else
888→                    {
889→                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
890→                                                    pBuffer, in_tensor_ch);
891→                    }
892→                    pBuffer += in_tensor_ch;
893→                }
894→            }
895→
896→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
897→            {
898→                pOut =
899→                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
900→                                                                    (u16_t*)in_tmp_buf,
901→                                                                    out_tensor_ch,
902→                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
903→                                                                    pre_rshift,
904→                                                                    out_scale,
905→                                                                    post_rshift,
906→                                                                    bias,
907→                                                                    pOut);
908→                /* counter reset */
909→                pBuffer = (u16_t*)in_tmp_buf;
910→            }
911→        }
912→    }
913→
914→    /* check if there is left-over for compute */
915→    if (pBuffer != (u16_t*)in_tmp_buf)
916→    {
917→        const q7_t *pA = ker_weight;
918→        int       i;
919→        for (i = 0; i < out_tensor_ch; i++)
920→        {
921→            q31_t     sum = bias[i];
922→            u16_t    *pB = (u16_t*)in_tmp_buf;
923→
924→            /* basically each time it process 4 entries */
925→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
926→            while (colCnt)
927→            {
928→                q31_t     inA1, inA2;
929→                q31_t     inB1, inB2;
930→
931→                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
932→                inB1 = *__SIMD32(pB)++;
933→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
934→                inB2 = *__SIMD32(pB)++;
935→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
936→                colCnt--;
937→            }
938→
939→            //since in_tensor_ch is multiple of 4 (input constraints), the
940→            //following codes will not be reached
941→            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
942→            // while (colCnt)
943→            // {
944→            //     q7_t      inA1 = *pA++;
945→            //     u16_t     inB1 = *pB++;
946→            //     sum += inA1 * inB1;
947→            //     colCnt--;
948→            // }
949→
950→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
951→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
952→        }
953→    }
954→#else
955→    int       i, j, k, l, m, n;
956→    int       conv_out;
957→    int       in_row, in_col;
958→
959→    for (i = 0; i < out_tensor_ch; i++)
960→    {
961→        for (j = 0; j < out_tensor_dim_y; j++)
962→        {
963→            for (k = 0; k < out_tensor_dim_x; k++)
964→            {
965→                conv_out = bias[i];
966→                for (m = 0; m < ker_dim_y; m++)
967→                {
968→                    for (n = 0; n < ker_dim_x; n++)
969→                    {
970→                        /* if-for implementation */
971→                        in_row = stride_y * j + m - pad_y;
972→                        in_col = stride_x * k + n - pad_x;
973→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
974→                        {
975→                            for (l = 0; l < in_tensor_ch; l++)
976→                            {
977→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
978→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
979→                            }
980→                        }
981→                    }
982→                }
983→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
984→                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
985→            }
986→        }
987→    }
988→#endif
989→#endif  //ENA_EMPTY_FUN
990→
991→    /* Return to application */
992→    return 0;
993→}
