 926→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
 927→                {
 928→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
 929→                    {
 930→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
 931→                    }
 932→                    else
 933→                    {
 934→                        nn_dup_s8_s16_reordered((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
 935→                                                    pBuffer, in_tensor_ch);
 936→                    }
 937→                    pBuffer += in_tensor_ch;
 938→                }
 939→            }
 940→
 941→            if (pBuffer == in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
 942→            {
 943→                pOut =
 944→                    nn_mat_mul_kernel_q7_q15_q15_reordered_bias_2sft(ker_weight,
 945→                                                                     in_tmp_buf,
 946→                                                                     out_tensor_ch,
 947→                                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
 948→                                                                     pre_rshift,
 949→                                                                     out_scale,
 950→                                                                     post_rshift,
 951→                                                                     bias,
 952→                                                                     pOut);
 953→                /* counter reset */
 954→                pBuffer = in_tmp_buf;
 955→            }
 956→        }
 957→    }
 958→
 959→    /* check if there is left-over for compute */
 960→    if (pBuffer != in_tmp_buf)
 961→    {
 962→        const q7_t *pA = ker_weight;
 963→        int       i;
 964→        for (i = 0; i < out_tensor_ch; i++)
 965→        {
 966→            q31_t     sum = bias[i];
 967→            q15_t    *pB = in_tmp_buf;
 968→
 969→            /* basically each time it process 4 entries */
 970→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
 971→            while (colCnt)
 972→            {
 973→                q31_t     inA1, inA2;
 974→                q31_t     inB1, inB2;
 975→
 976→                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
 977→                inB1 = *__SIMD32(pB)++;
 978→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
 979→                inB2 = *__SIMD32(pB)++;
 980→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
 981→                colCnt--;
 982→            }
 983→
 984→            //since in_tensor_ch is multiple of 4 (input constraints), the
 985→            //following codes will not be reached
 986→            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
 987→            // while (colCnt)
 988→            // {
 989→            //     q7_t      inA1 = *pA++;
 990→            //     q15_t     inB1 = *pB++;
 991→            //     sum += inA1 * inB1;
 992→            //     colCnt--;
 993→            // }
 994→
 995→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
 996→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 16);
 997→        }
 998→    }
 999→#else
1000→    int       i, j, k, l, m, n;
1001→    int       conv_out;
1002→    int       in_row, in_col;
1003→
1004→    for (i = 0; i < out_tensor_ch; i++)
1005→    {
1006→        for (j = 0; j < out_tensor_dim_y; j++)
1007→        {
1008→            for (k = 0; k < out_tensor_dim_x; k++)
1009→            {
1010→                conv_out = bias[i];
1011→                for (m = 0; m < ker_dim_y; m++)
1012→                {
1013→                    for (n = 0; n < ker_dim_x; n++)
1014→                    {
1015→                        /* if-for implementation */
1016→                        in_row = stride_y * j + m - pad_y;
1017→                        in_col = stride_x * k + n - pad_x;
1018→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
1019→                        {
1020→                            for (l = 0; l < in_tensor_ch; l++)
1021→                            {
1022→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
1023→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
1024→                            }
1025→                        }
1026→                    }
1027→                }
1028→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
1029→                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 16);
1030→            }
1031→        }
1032→    }
1033→#endif
1034→#endif  //ENA_EMPTY_FUN
1035→    /* Return to application */
1036→    return 0;
1037→}
