185→                    }
186→                    pBuffer += in_tensor_ch;
187→                }
188→            }
189→
190→            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
191→            {
192→                pOut = nn_mat_mul_kernel_u8_q15_bias_2sft(ker_weight,
193→                        (u8_t*)in_tmp_buf,
194→                        out_tensor_ch,
195→                        in_tensor_ch * ker_dim_x * ker_dim_y,
196→                        pre_rshift,
197→                        out_scale,
198→                        post_rshift,
199→                        bias,
200→                        pOut);
201→                /* counter reset */
