839→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
840→                {
841→                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
842→                    {
843→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
844→                    }
845→                    else
846→                    {
847→                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
848→                                                    pBuffer, in_tensor_ch);
849→                    }
850→                    pBuffer += in_tensor_ch;
851→                }
852→            }
853→
854→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
855→            {
856→                pOut =
857→                    nn_mat_mul_kernel_q7_u16_q15_reordered_bias_2sft(ker_weight,
858→                                                                     (u16_t*)in_tmp_buf,
859→                                                                     out_tensor_ch,
860→                                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
861→                                                                     pre_rshift,
862→                                                                     out_scale,
863→                                                                     post_rshift,
864→                                                                     bias,
865→                                                                     pOut);
866→                /* counter reset */
867→                pBuffer = (u16_t*)in_tmp_buf;
868→            }
869→        }
870→    }
871→
872→    for (; i_out_y < out_tensor_dim_y; i_out_y++)
873→    {
874→        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
875→        {
876→            /* This part implements the im2col function */
877→            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
878→            {
879→                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
880→                {
881→                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
882→                    {
883→                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
884→                    }
885→                    else
886→                    {
887→                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
888→                                                    pBuffer, in_tensor_ch);
889→                    }
890→                    pBuffer += in_tensor_ch;
891→                }
892→            }
893→
894→            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
895→            {
896→                pOut =
897→                    nn_mat_mul_kernel_q7_u16_q15_reordered_bias_2sft(ker_weight,
898→                                                                     (u16_t*)in_tmp_buf,
899→                                                                     out_tensor_ch,
900→                                                                     in_tensor_ch * ker_dim_x * ker_dim_y,
901→                                                                     pre_rshift,
902→                                                                     out_scale,
903→                                                                     post_rshift,
904→                                                                     bias,
905→                                                                     pOut);
906→                /* counter reset */
907→                pBuffer = (u16_t*)in_tmp_buf;
908→            }
909→        }
910→    }
911→
912→    /* check if there is left-over for compute */
913→    if (pBuffer != (u16_t*)in_tmp_buf)
914→    {
915→        const q7_t *pA = ker_weight;
916→        int       i;
917→        for (i = 0; i < out_tensor_ch; i++)
918→        {
919→            q31_t     sum = bias[i];
920→            u16_t    *pB = (u16_t*)in_tmp_buf;
921→
922→            /* basically each time it process 4 entries */
923→            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
924→            while (colCnt)
925→            {
926→                q31_t     inA1, inA2;
927→                q31_t     inB1, inB2;
928→
929→                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
930→                inB1 = *__SIMD32(pB)++;
931→                sum = NDS_DSP_KMADA(sum, inA1, inB1);
932→                inB2 = *__SIMD32(pB)++;
933→                sum = NDS_DSP_KMADA(sum, inA2, inB2);
934→                colCnt--;
935→            }
936→
937→            //since in_tensor_ch is multiple of 4 (input constraints), the
938→            //following codes will not be reached
939→            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
940→            // while (colCnt)
941→            // {
942→            //     q7_t      inA1 = *pA++;
943→            //     u16_t     inB1 = *pB++;
944→            //     sum += inA1 * inB1;
945→            //     colCnt--;
946→            // }
947→
948→            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
949→            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 16);
950→        }
951→    }
952→#else
953→    int       i, j, k, l, m, n;
954→    int       conv_out;
955→    int       in_row, in_col;
956→
957→    for (i = 0; i < out_tensor_ch; i++)
958→    {
959→        for (j = 0; j < out_tensor_dim_y; j++)
960→        {
961→            for (k = 0; k < out_tensor_dim_x; k++)
962→            {
963→                conv_out = bias[i];
964→                for (m = 0; m < ker_dim_y; m++)
965→                {
966→                    for (n = 0; n < ker_dim_x; n++)
967→                    {
968→                        /* if-for implementation */
969→                        in_row = stride_y * j + m - pad_y;
970→                        in_col = stride_x * k + n - pad_x;
971→                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
972→                        {
973→                            for (l = 0; l < in_tensor_ch; l++)
974→                            {
975→                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
976→                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
977→                            }
978→                        }
979→                    }
980→                }
981→                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
982→                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 16);
983→            }
984→        }
985→    }
986→#endif
987→#endif  //ENA_EMPTY_FUN
988→
989→    /* Return to application */
990→    return 0;
991→}
